const RichTextEditor = ({ modules, formats, ...props }) => {
  const quillRef = useRef(null);
  const { dataUser } = useAuth();

  const openNotification = (title, type, value) => {
    toast.push(
      <Notification title={title} type={type}>
        {value}
      </Notification>,
    );
  };

  const modulesDefault = {
    toolbar: [
      [
        'bold',
        'italic',
        'underline',
        { align: null },
        { align: 'center' },
        { align: 'right' },
        { align: 'justify' },
        { list: 'ordered' },
        { list: 'bullet' },
        'image',
      ],
    ],
  };

  const formatDefault = ['bold', 'italic', 'align', 'list', 'bullet', 'indent', 'image'];

  const uploadImages = (quill) => {
    var input = document.createElement('input');
    input.setAttribute('type', 'file');
    input.click();
    input.onchange = () => {
      const file = input.files[0];
      if (file) {
        const maxSize = 2 * 1024 * 1024; // 2MB in bytes

        if (file.size <= maxSize) {
          const formData = new FormData();
          formData.append('file', file);
          fetch(`${process.env.REACT_APP_API_HOST}/files`, {
            method: 'POST',
            body: formData,
            headers: {
              Authorization: `Bearer ${dataUser?.access_token} `,
            },
          })
            .then(async (response) => {
              const result = await response.json();
              const resultUpload = {
                type: 'success',
                message: 'success',
                data: result,
              };
              const range = quill.getEditor().getSelection();
              quill.getEditor().insertEmbed(range.index, 'image', resultUpload.data.url);
            })

            .catch((error) => {
              const err = {
                type: 'error',
                message: 'API Upload Error',
                data: error,
              };
              openNotification('Error', 'danger', err?.message);
            });
        } else {
          const err = {
            type: 'error',
            message: 'File tidak boleh melebihi 2MB',
            data: {},
          };
          openNotification('Error', 'danger', err?.message);
        }
      } else {
        const err = {
          type: 'error',
          message: 'API Upload Error',
          data: {},
        };
        openNotification('Error', 'danger', err?.message);
      }
    };
  };

  useEffect(() => {
    quillRef.current
      ?.getEditor()
      .getModule('toolbar')
      .addHandler('image', () => {
        uploadImages(quillRef.current);
      });
  }, []);

  return (
    <ReactQuill
      ref={quillRef}
      style={props.style ? props.style : { height: '300px', marginBottom: '24px' }}
      theme="snow"
      initialValue=""
      modules={modules || modulesDefault}
      formats={formats || formatDefault}
      {...props}
    />
  );
};

export default RichTextEditor;
